arguments.new_str:
using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");
            entity.HasIndex(p => p.Sku);

            // EF Core 9 breaking change: discriminator property renamed from
            // "Discriminator" to "$type". Preserve the old name for compatibility
            // with existing 500K documents and direct SQL queries.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 breaking change: id format changed from "Product|123"
            // to just "123". Preserve the old format for existing documents.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id")
                .HasValueGenerator<LegacyIdValueGenerator>();
        });
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; }  }

// Generates id values in the legacy "Product|{key}" format used by EF Core 8
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class LegacyIdValueGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
        => $"Product|{entry.Property("Id").CurrentValue}";
}

